(4,"Échantillonnage et bootstrap",[("qcm","Que quantifie l’erreur standard ?",["La variabilité d’un estimateur","La dispersion brute seulement","Le nombre de colonnes","Une erreur de saisie"],"A","Elle mesure la variabilité d’échantillonnage."),("true_false","Le bootstrap rééchantillonne avec remise.",["Vrai","Faux","Jamais","Seulement deux fois"],"A","Les réplications bootstrap tirent avec remise."),("comprehension","Un intervalle de confiance à 95 % signifie-t-il 95 % de probabilité pour ce paramètre fixe ?",["Non, en interprétation fréquentiste","Oui toujours","Seulement avec pandas","Seulement si n=100"],"A","Le niveau concerne la procédure répétée."),("mini_challenge","Quel biais menace un sondage diffusé seulement aux clients actifs ?",["Biais de sélection","Biais de compilation","Biais de syntaxe","Biais de tri"],"A","Les non-actifs ne peuvent pas être représentés.")]),
