(10,"Évaluation des modèles",[("qcm","Quel jeu doit rester verrouillé jusqu’à l’évaluation finale ?",["Test","Train","Documentation","Dictionnaire"],"A","Le test final doit rester indépendant."),("true_false","La standardisation doit être apprise séparément dans chaque fold.",["Vrai","Faux","Jamais","Seulement pour les arbres"],"A","Sinon les folds de validation influencent la transformation."),("comprehension","Que suggère un score train excellent et validation faible ?",["Surapprentissage","Sous-échantillonnage certain","Causalité","Absence de modèle"],"A","Le modèle généralise mal."),("mini_challenge","Pourquoi l’importance de permutation peut-elle être trompeuse avec variables corrélées ?",["Une variable peut être remplacée par sa corrélée","Elle devient causale","La cible disparaît","Les folds doublent"],"A","L’information redondante réduit la baisse de score individuelle.")]),
(11,"Communication",[("qcm","Quel ordre sert une restitution métier ?",["Question, méthode, résultat, limites, recommandation","Code, code, code","Conclusion avant données sans preuve","Graphiques sans titres"],"A","La narration relie besoin, preuve et action."),("true_false","Un notebook reproductible doit pouvoir être exécuté depuis un environnement propre.",["Vrai","Faux","Seulement en local","Jamais"],"A","L’état caché doit être éliminé."),("comprehension","Que doit distinguer une restitution honnête ?",["Faits, interprétations et décisions","Couleurs et polices","Python et clavier","CSV et écran"],"A","Ces niveaux n’ont pas le même statut de preuve."),("mini_challenge","Quel garde-fou accompagne une recommandation sensible ?",["Revue humaine et suivi par sous-groupe","Automatisation sans contrôle","Suppression des limites","Collecte maximale"],"A","La supervision et l’équité réduisent le risque.")]),
